#!/bin/bash
# Test set-then-get round trip for 200 READ_WRITE VSS properties via dumpsys
# (100 INT + 100 BOOLEAN, names taken verbatim from the generated VTS ground-truth table).
# FLOAT/STRING properties are excluded: the debug dump interface is INT-only by contract;
# their persistence is already covered by VTS VssPropertyRoundTrip (floatValues path).
#
# Usage: ./test_200_signals.sh [adb_serial]
#   e.g. ./test_200_signals.sh 0.0.0.0:6520

SERIAL="${1:-}"
ADB="adb"
[ -n "$SERIAL" ] && ADB="adb -s $SERIAL"
SVC="android.hardware.automotive.vehicle.IVehicle/default"

PASS=0; FAIL=0; FAILED_PROPS=()

test_prop() {
  local name="$1" val="$2"
  local set_out get_out
  set_out=$($ADB shell dumpsys "$SVC" --set "$name" -i "$val" 2>&1)
  if [[ "$set_out" != *"SET OK"* ]]; then
    FAIL=$((FAIL+1)); FAILED_PROPS+=("$name (set failed: $set_out)"); return
  fi
  get_out=$($ADB shell dumpsys "$SVC" --get "$name" 2>&1)
  if [[ "$get_out" == *"value: $val"* ]]; then
    PASS=$((PASS+1))
  else
    FAIL=$((FAIL+1)); FAILED_PROPS+=("$name (expected $val, got: $get_out)")
  fi
}

echo "Testing 200 READ_WRITE properties (100 INT with value 37, 100 BOOLEAN with value 1)..."
START=$(date +%s)

